class Solution:
    def destroyTargets(self, nums, space):
        best_count = 0
        best_val = None
        for seed in nums:
            r = seed % space
            count = sum(1 for x in nums if x % space == r)
            if count > best_count or (count == best_count and (best_val is None or seed < best_val)):
                best_count = count
                best_val = seed
        return best_val

