class Solution:
    def destroyTargets(self, nums, space):
        from collections import defaultdict
        cnt = defaultdict(int)
        for x in nums:
            cnt[x % space] += 1
        best = max(cnt.values())
        ans = None
        for x in nums:
            if cnt[x % space] == best and (ans is None or x < ans):
                ans = x
        return ans

