var destroyTargets = function(nums, space) {
    const cnt = new Map();
    for (const x of nums) {
        const r = ((x % space) + space) % space;
        cnt.set(r, (cnt.get(r) || 0) + 1);
    }
    let best = 0;
    for (const v of cnt.values()) best = Math.max(best, v);
    let ans = Infinity;
    for (const x of nums) {
        const r = ((x % space) + space) % space;
        if (cnt.get(r) === best && x < ans) ans = x;
    }
    return ans;
};
